const body = $input.first().json;
const projectCode = $json.body?.project_code || null;
const baseUrl = $json.body?.base_url || '';

// If the HTTP node returns parsed XML, attempt to extract responses.
// Fallback: treat the response as a single item if no array is found.
let responses = [];
if (body && Array.isArray(body['d:response'])) {
  responses = body['d:response'];
} else if (body && body['d:response']) {
  responses = [body['d:response']];
} else if (Array.isArray(body)) {
  responses = body;
} else if (body) {
  responses = [body];
}

const evidence = responses.map((item, index) => {
  const href = item['d:href'] || item.href || ('/file-' + index);
  const props = item['d:propstat']?.['d:prop'] || item.prop || {};
  const isCollection = props['d:resourcetype']?.['d:collection'] !== undefined;
  const name = props['d:displayname'] || href.split('/').pop() || 'Untitled';
  const lastMod = props['d:getlastmodified'] || null;
  const etag = props['d:getetag'] || null;

  let hash;
  try {
    const crypto = require('crypto');
    hash = crypto.createHash('sha256').update(href + (lastMod || '')).digest('hex');
  } catch (e) {
    hash = 'oc-' + index + '-' + (lastMod || 'unknown');
  }

  return {
    evidence_id: 'oc-' + index,
    source_type: 'owncloud',
    source_uri: baseUrl + href,
    title: name,
    project_code: projectCode,
    contract_no: $json.body?.contract_no || null,
    revision: etag ? etag.replace(/["]/g, '') : null,
    timestamp: lastMod,
    excerpt: isCollection ? 'Directory: ' + name : name,
    hash_sha256: hash,
    confidence: 'medium',
    tags: ['owncloud', isCollection ? 'directory' : 'file'],
    metadata: {
      href: href,
      is_collection: isCollection,
      size: props['d:getcontentlength'] || null
    }
  };
}).filter(e => e.title && e.title !== '');

return [{ json: { evidence: evidence } }];
